// src/pages/HistorialCotizaciones.jsx
import React, { useEffect, useState } from 'react';
import api from '../api/api';
import { FaEye, FaFilePdf,  } from 'react-icons/fa';

const HistorialCotizaciones = () => {
  const [cotizaciones, setCotizaciones] = useState([]);

  useEffect(() => {
    const cargarCotizaciones = async () => {
      try {
        const res = await api.get('/cotizaciones');
        setCotizaciones(res.data);
      } catch (error) {
        console.error("Error al cargar historial:", error);
      }
    };
    cargarCotizaciones();
  }, []);

  return (
    <div className="container-fluid p-4" style={{ marginLeft: "250px", width: "calc(100% - 250px)" }}>
      <h2 className="fw-bold mb-4">Historial de Cotizaciones</h2>
      <div className="card shadow-sm border-0 rounded-4 overflow-hidden">
        <div className="table-responsive">
          <table className="table table-hover align-middle mb-0">
            <thead className="table-dark">
              <tr>
                <th className="px-4">Fecha</th>
                <th>Cliente</th>
                <th>Total</th>
                <th>Estado</th>
                <th className="text-end px-4">Acciones</th>
              </tr>
            </thead>
            <tbody>
              {cotizaciones.map((c) => (
                <tr key={c._id}>
                  <td className="px-4">{new Date(c.createdAt).toLocaleDateString()}</td>
                  <td className="fw-bold">{c.Nombre} {c.Apellido || ""}</td>
                  <td className="text-primary fw-bold">${c.Total.toFixed(2)}</td>
                  <td>
                    <span className="badge bg-info text-dark">{c.estado || 'Pendiente'}</span>
                  </td>
                  <td className="text-end px-4">
                    <button className="btn btn-sm btn-outline-primary me-2"><FaEye /></button>
                    <button className="btn btn-sm btn-outline-danger"><FaFilePdf /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default HistorialCotizaciones;
